def generate_tone(frequency, duration, sample_rate=44100, volume=0.5):
    """Generate a sine wave tone as numpy array (stereo)."""
    t = np.linspace(0, duration, int(sample_rate * duration), False)
    # Add harmonics for richer sound
    wave = (np.sin(2 * np.pi * frequency * t) * 0.6 +
            np.sin(2 * np.pi * frequency * 2 * t) * 0.2 +
            np.sin(2 * np.pi * frequency * 0.5 * t) * 0.2)
    # Apply envelope
    envelope = np.ones_like(t)
    attack = int(0.01 * sample_rate)
    release = int(0.05 * sample_rate)
    if attack > 0:
        envelope[:attack] = np.linspace(0, 1, attack)
    if release > 0 and release < len(t):
        envelope[-release:] = np.linspace(1, 0, release)
    wave = wave * envelope * volume
    wave_int = (wave * 32767).astype(np.int16)
    # Make stereo by stacking the mono channel twice -> shape (N, 2)
    stereo_wave = np.column_stack([wave_int, wave_int])
    return stereo_wave


